import{_ as o,c as t,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Добавление учетной записи: OAuth и Refresh Token | Antigravity Tools","description":"Изучите способы добавления учетной записи в Antigravity Tools. Добавление учетной записи через OAuth авторизацию или Refresh Token вручную, поддерживает пакетный импорт, обработку сбоев обратного вызова и проверку пула учетных записей.","frontmatter":{"title":"Добавление учетной записи: OAuth и Refresh Token | Antigravity Tools","sidebarTitle":"Добавление вашей Google учетной записи","subtitle":"Добавление учетной записи: OAuth/Refresh Token двухканальный и лучшие практики","description":"Изучите способы добавления учетной записи в Antigravity Tools. Добавление учетной записи через OAuth авторизацию или Refresh Token вручную, поддерживает пакетный импорт, обработку сбоев обратного вызова и проверку пула учетных записей.","tags":["управление учетными записями","OAuth","refresh_token","Google","Antigravity Tools"],"prerequisite":["start-getting-started"],"duration":15,"order":4},"headers":[],"relativePath":"ru/lbjlaq/Antigravity-Manager/start/add-account/index.md","filePath":"ru/lbjlaq/Antigravity-Manager/start/add-account/index.md"}'),c={name:"ru/lbjlaq/Antigravity-Manager/start/add-account/index.md"};function d(l,e,s,n,i,h){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="добавление-учетнои-записи-oauth-refresh-token-двухканальныи-и-лучшие-практики" tabindex="-1">Добавление учетной записи: OAuth/Refresh Token двухканальный и лучшие практики <a class="header-anchor" href="#добавление-учетнои-записи-oauth-refresh-token-двухканальныи-и-лучшие-практики" aria-label="Permalink to &quot;Добавление учетной записи: OAuth/Refresh Token двухканальный и лучшие практики&quot;">​</a></h1><p>В Antigravity Tools «добавление учетной записи» — это запись <code>refresh_token</code> Google учетной записи в локальный пул учетных записей, чтобы последующие запросы обратного прокси могли ротационно использовать его. Вы можете авторизоваться через OAuth в один клик или напрямую вставить <code>refresh_token</code> для ручного добавления.</p><h2 id="чему-вы-научитесь" tabindex="-1">Чему вы научитесь <a class="header-anchor" href="#чему-вы-научитесь" aria-label="Permalink to &quot;Чему вы научитесь&quot;">​</a></h2><ul><li>Добавить учетные записи в Antigravity Tools через OAuth или Refresh Token</li><li>Скопировать/вручную открыть ссылку авторизации и после успешного обратного вызова автоматически завершить добавление</li><li>При возникновении проблем с получением <code>refresh_token</code> или сбоем обратного вызова на <code>localhost</code> вы будете знать, как с этим обращаться</li></ul><h2 id="ваша-текущая-ситуация" tabindex="-1">Ваша текущая ситуация <a class="header-anchor" href="#ваша-текущая-ситуация" aria-label="Permalink to &quot;Ваша текущая ситуация&quot;">​</a></h2><ul><li>Вы нажали «OAuth авторизация», но крутится спиннер или браузер сообщает <code>localhost refused to connect</code></li><li>Авторизация прошла успешно, но выводит «Не получен Refresh Token»</li><li>У вас только <code>refresh_token</code>, и вы не знаете, как一次性 массово импортировать</li></ul><h2 id="когда-использовать-этот-метод" tabindex="-1">Когда использовать этот метод <a class="header-anchor" href="#когда-использовать-этот-метод" aria-label="Permalink to &quot;Когда использовать этот метод&quot;">​</a></h2><ul><li>Вы хотите использовать самый надежный способ добавления учетной записи (приоритет OAuth)</li><li>Вам больше важна возможность миграции/резервного копирования (Refresh Token больше подходит как «актив пула учетных записей»)</li><li>Вам нужно добавить много учетных записей, вы хотите массово импортировать <code>refresh_token</code> (поддерживается извлечение из текста/JSON)</li></ul><h2 id="🎒-подготовка-к-началу" tabindex="-1">🎒 Подготовка к началу <a class="header-anchor" href="#🎒-подготовка-к-началу" aria-label="Permalink to &quot;🎒 Подготовка к началу&quot;">​</a></h2><ul><li>Вы уже установили и можете открыть Antigravity Tools</li><li>Вы знаете, где вход: в боковой панели перейдите на страницу <code>Accounts</code> (маршрут см. <code>source/lbjlaq/Antigravity-Manager/src/App.tsx</code>)</li></ul><div class="info custom-block"><p class="custom-block-title">В этом уроке два ключевых слова</p><p><strong>OAuth</strong>: вид «переход в браузер для входа и авторизации». Antigravity Tools локально временно создаст адрес обратного вызова (<code>http://localhost/127.0.0.1/[::1]:&lt;port&gt;/oauth-callback</code> в зависимости от системной ситуации IPv4/IPv6), дождется <code>code</code> из браузера, а затем обменяет token. (реализация см. <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs</code>)</p><p><strong>refresh_token</strong>: вид «доверенный токен, который можно использовать долгосрочно для обновления access_token». При добавлении учетной записи в этом проекте он будет использован сначала для обмена на access_token, а затем получит реальный email от Google для сохранения на диск. (реализация см. <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs</code>)</p></div><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p>Суть «добавления учетной записи» в Antigravity Tools — это сделать две вещи:</p><ol><li>Найти доступный <code>refresh_token</code></li><li>Использовать его для обмена на access_token, а затем получить реальный email от Google и записать учетную запись в локальный пул учетных записей</li></ol><p>Оно предоставляет три входа:</p><ul><li>Импорт/экспорт JSON: подходит, когда вам явно нужно сделать «управляемое резервное копирование»</li><li>Импорт из DB: подходит, когда вы берете состояние входа Antigravity/IDE как авторитетный источник (по умолчанию ищет <code>state.vscdb</code>, также поддерживает ручной выбор файла)</li><li>Импорт из V1: подходит для автоматического сканирования и импорта старых данных из каталога V1</li></ul><p>Кроме того, есть путь «автоматическая синхронизация»: она будет периодически читать <code>refresh_token</code> в DB, если он отличается от текущей учетной записи, автоматически выполнит импорт из DB; если он совпадает, то пропустит, чтобы сэкономить трафик.</p><h2 id="следуите-за-нами" tabindex="-1">Следуйте за нами <a class="header-anchor" href="#следуите-за-нами" aria-label="Permalink to &quot;Следуйте за нами&quot;">​</a></h2><h3 id="шаг-1-откроите-диалог-«добавление-учетнои-записи»" tabindex="-1">Шаг 1: откройте диалог «Добавление учетной записи» <a class="header-anchor" href="#шаг-1-откроите-диалог-«добавление-учетнои-записи»" aria-label="Permalink to &quot;Шаг 1: откройте диалог «Добавление учетной записи»&quot;">​</a></h3><p><strong>Почему</strong> Все входы для добавления единогласно собраны на странице <code>Accounts</code>.</p><p>В Antigravity Tools откройте страницу <code>Accounts</code>, нажмите кнопку <strong>Add Account</strong> справа (компонент: <code>AddAccountDialog</code>).</p><p><strong>Вы должны увидеть</strong>: всплывает диалог с тремя вкладками: <code>OAuth</code> / <code>Refresh Token</code> / <code>Import</code> (см. <code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx</code>).</p><h3 id="шаг-2-в-первую-очередь-используите-oauth-авторизацию-в-один-клик-рекомендуется" tabindex="-1">Шаг 2: в первую очередь используйте OAuth авторизацию в один клик (рекомендуется) <a class="header-anchor" href="#шаг-2-в-первую-очередь-используите-oauth-авторизацию-в-один-клик-рекомендуется" aria-label="Permalink to &quot;Шаг 2: в первую очередь используйте OAuth авторизацию в один клик (рекомендуется)&quot;">​</a></h3><p><strong>Почему</strong> Это путь по умолчанию, рекомендуемый продуктом: приложение само генерирует ссылку авторизации, автоматически открывает браузер, а после обратного вызова автоматически завершает сохранение.</p><ol><li>Переключитесь на вкладку <code>OAuth</code>.</li><li>Сначала скопируйте ссылку авторизации: после открытия диалога он автоматически вызовет <code>prepare_oauth_url</code> для предварительной генерации URL (вызов фронтенда см. <code>AddAccountDialog.tsx:111-125</code>; генерация и прослушивание см. <code>oauth_server.rs</code>).</li><li>Нажмите <strong>Start OAuth</strong> (соответствует фронтенду <code>startOAuthLogin()</code> / бэкенду <code>start_oauth_login</code>), чтобы приложение открыло браузер по умолчанию и начало ждать обратного вызова.</li></ol><p><strong>Вы должны увидеть</strong>:</p><ul><li>В диалоге появляется копируемая ссылка авторизации (имя события: <code>oauth-url-generated</code>)</li><li>Браузер открывает страницу авторизации Google; после авторизации происходит перенаправление на локальный адрес, и отображается «Authorization Successful!» (<code>oauth_success_html()</code>)</li></ul><h3 id="шаг-3-когда-oauth-не-завершается-автоматически-используите-«завершить-oauth»-для-ручного-завершения" tabindex="-1">Шаг 3: когда OAuth не завершается автоматически, используйте «Завершить OAuth» для ручного завершения <a class="header-anchor" href="#шаг-3-когда-oauth-не-завершается-автоматически-используите-«завершить-oauth»-для-ручного-завершения" aria-label="Permalink to &quot;Шаг 3: когда OAuth не завершается автоматически, используйте «Завершить OAuth» для ручного завершения&quot;">​</a></h3><p><strong>Почему</strong> Процесс OAuth разделен на два этапа: браузер авторизуется и получает <code>code</code>, затем приложение использует <code>code</code> для обмена на token. Даже если вы не нажимали «Start OAuth», пока вы вручную откроете ссылку авторизации и завершите обратный вызов, диалог будет пытаться автоматически завершиться; если не завершилось, вы можете вручную нажать один раз.</p><ol><li>Если вы «скопировали ссылку в свой браузер» (а не в браузер по умолчанию), после обратного вызова авторизации приложение получит событие <code>oauth-callback-received</code> и автоматически вызовет <code>completeOAuthLogin()</code> (см. <code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx:67-109</code>).</li><li>Если вы не видите автоматического завершения, нажмите в диалоге кнопку <strong>Finish OAuth</strong> (соответствует бэкенду <code>complete_oauth_login</code>).</li></ol><p><strong>Вы должны увидеть</strong>: диалог подсказывает об успехе и автоматически закрывается; в списке <code>Accounts</code> появляется новая учетная запись.</p><div class="tip custom-block"><p class="custom-block-title">Совет: при сбое обратного вызова сначала скопируйте ссылку</p><p>Бэкенд будет стараться одновременно прослушивать IPv6 <code>::1</code> и IPv4 <code>127.0.0.1</code>, и в зависимости от ситуации прослушивания выберет <code>localhost/127.0.0.1/[::1]</code> как адрес обратного вызова, в основном чтобы избежать «браузер разбирает localhost как IPv6» вызывающего сбой подключения. (см. <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code>)</p></div><h3 id="шаг-4-ручное-добавление-через-refresh-token-поддерживает-пакет" tabindex="-1">Шаг 4: ручное добавление через Refresh Token (поддерживает пакет) <a class="header-anchor" href="#шаг-4-ручное-добавление-через-refresh-token-поддерживает-пакет" aria-label="Permalink to &quot;Шаг 4: ручное добавление через Refresh Token (поддерживает пакет)&quot;">​</a></h3><p><strong>Почему</strong> Когда вы не можете получить <code>refresh_token</code> (или вам больше важна возможность миграции), прямое добавление через Refresh Token более контролируемо.</p><ol><li>Переключитесь на вкладку <code>Refresh Token</code>.</li><li>Вставьте <code>refresh_token</code> в текстовое поле.</li></ol><p>Поддерживаемые формы ввода (фронтенд будет разбирать и массово добавлять):</p><table tabindex="0"><thead><tr><th>Тип ввода</th><th>Пример</th><th>Логика разбора</th></tr></thead><tbody><tr><td>Чистый текст token</td><td><code>1//abc...</code></td><td>Регулярное извлечение: <code>/1\\/\\/[a-zA-Z0-9_\\-]+/g</code> (см. <code>AddAccountDialog.tsx:213-220</code>)</td></tr><tr><td>Встроенный в большой фрагмент текста</td><td>логи/экспорт текст содержит несколько <code>1//...</code></td><td>Регулярное массовое извлечение и дедупликация (см. <code>AddAccountDialog.tsx:213-224</code>)</td></tr><tr><td>Массив JSON</td><td><code>[{&quot;refresh_token&quot;:&quot;1//...&quot;}]</code></td><td>Разбор массива и извлечение <code>item.refresh_token</code> (см. <code>AddAccountDialog.tsx:198-207</code>)</td></tr></tbody></table><p>После нажатия <strong>Confirm</strong> диалог будет по очереди вызывать <code>onAdd(&quot;&quot;, token)</code> для каждого token (см. <code>AddAccountDialog.tsx:231-248</code>), в итоге перейдет к бэкенду <code>add_account</code>.</p><p><strong>Вы должны увидеть</strong>:</p><ul><li>Диалог отображает прогресс пакетной обработки (например <code>1/5</code>)</li><li>После успеха в списке <code>Accounts</code> появляются новые учетные записи</li></ul><h3 id="шаг-5-подтвердите-что-«пул-учетных-записеи-доступен»" tabindex="-1">Шаг 5: подтвердите, что «пул учетных записей доступен» <a class="header-anchor" href="#шаг-5-подтвердите-что-«пул-учетных-записеи-доступен»" aria-label="Permalink to &quot;Шаг 5: подтвердите, что «пул учетных записей доступен»&quot;">​</a></h3><p><strong>Почему</strong> Успешное добавление не равно «немедленно можно стабильно использовать». После успешного добавления бэкенд автоматически запустит «обновление квоты», а при работе Proxy попытается перезагрузить token pool, чтобы изменения вступили в силу немедленно.</p><p>Вы можете подтвердить следующими двумя сигналами:</p><ol><li>Учетная запись появляется в списке и отображает email (email берется от бэкенда <code>get_user_info</code>, а не email, который вы ввели).</li><li>Квота/информация о подписке начинает обновляться (бэкенд автоматически вызовет <code>internal_refresh_account_quota</code>)</li></ol><p><strong>Вы должны увидеть</strong>: после добавления нет необходимости вручную нажимать обновление, учетные записи начинают появляться информация о квоте (в зависимости от того, отобразится ли интерфейс).</p><h2 id="контрольная-проверка-✅" tabindex="-1">Контрольная проверка ✅ <a class="header-anchor" href="#контрольная-проверка-✅" aria-label="Permalink to &quot;Контрольная проверка ✅&quot;">​</a></h2><ul><li>[ ] В списке <code>Accounts</code> вы можете увидеть новую учетную запись с email</li><li>[ ] Нет состояния «loading» дольше вашего допустимого времени (после обратного вызова OAuth должно быстро завершиться)</li><li>[ ] Если вы работаете с Proxy, новые учетные записи могут быстро участвовать в планировании (бэкенд попытается перезагрузить)</li></ul><h2 id="предостережения" tabindex="-1">Предостережения <a class="header-anchor" href="#предостережения" aria-label="Permalink to &quot;Предостережения&quot;">​</a></h2><h3 id="_1-oauth-выдает-«не-получен-refresh-token»" tabindex="-1">1) OAuth выдает «Не получен Refresh Token» <a class="header-anchor" href="#_1-oauth-выдает-«не-получен-refresh-token»" aria-label="Permalink to &quot;1) OAuth выдает «Не получен Refresh Token»&quot;">​</a></h3><p>Бэкенд при <code>start_oauth_login/complete_oauth_login</code> будет явно проверять, существует ли <code>refresh_token</code>; если нет, вернет текст с решением (см. <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs:45-56</code>).</p><p>Согласно подсказкам в исходном коде:</p><ol><li>Откройте <code>https://myaccount.google.com/permissions</code></li><li>Отзовите доступ <strong>Antigravity Tools</strong></li><li>Вернитесь в приложение и снова пройдите OAuth</li></ol><blockquote><p>Вы также можете перейти на путь Refresh Token этого урока.</p></blockquote><h3 id="_2-браузер-сообщает-localhost-refused-to-connect" tabindex="-1">2) Браузер сообщает <code>localhost refused to connect</code> <a class="header-anchor" href="#_2-браузер-сообщает-localhost-refused-to-connect" aria-label="Permalink to &quot;2) Браузер сообщает `localhost refused to connect`&quot;">​</a></h3><p>Обратный вызов OAuth требует, чтобы браузер отправил запрос на адрес обратного вызова. Для снижения вероятности сбоя бэкенд будет:</p><ul><li>Попытаться одновременно прослушивать <code>127.0.0.1</code> и <code>::1</code></li><li>Когда оба доступны, использовать <code>localhost</code>, в противном случае принудительно использовать <code>127.0.0.1</code> или <code>[::1]</code></li></ul><p>Соответствующая реализация см. <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code>.</p><h3 id="_3-переключение-на-другую-вкладку-отменит-подготовку-oauth" tabindex="-1">3) переключение на другую вкладку отменит подготовку OAuth <a class="header-anchor" href="#_3-переключение-на-другую-вкладку-отменит-подготовку-oauth" aria-label="Permalink to &quot;3) переключение на другую вкладку отменит подготовку OAuth&quot;">​</a></h3><p>Когда диалог переключается с <code>OAuth</code> на другую вкладку, фронтенд вызовет <code>cancelOAuthLogin()</code> и очистит URL (см. <code>AddAccountDialog.tsx:127-136</code>).</p><p>Если вы в процессе авторизации, не спешите переключать вкладку.</p><h3 id="_4-правильныи-неправильныи-пример-refresh-token" tabindex="-1">4) правильный/неправильный пример Refresh Token <a class="header-anchor" href="#_4-правильныи-неправильныи-пример-refresh-token" aria-label="Permalink to &quot;4) правильный/неправильный пример Refresh Token&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Пример</th><th>Распознается ли</th><th>Причина</th></tr></thead><tbody><tr><td><code>1//0gAbC...</code></td><td>✓</td><td>Соответствует правилу префикса <code>1//</code> (см. <code>AddAccountDialog.tsx:215-219</code>)</td></tr><tr><td><code>ya29.a0...</code></td><td>✗</td><td>Не соответствует правилу извлечения фронтенда, будет считаться недопустимым вводом</td></tr></tbody></table><h2 id="итог-урока" tabindex="-1">Итог урока <a class="header-anchor" href="#итог-урока" aria-label="Permalink to &quot;Итог урока&quot;">​</a></h2><ul><li>OAuth: подходит для «быстро», также поддерживает копирование ссылки в ваш часто используемый браузер и автоматическое/ручное завершение</li><li>Refresh Token: подходит для «надежно и с возможностью миграции», и поддерживает массовое извлечение <code>1//...</code> из текста/JSON</li><li>При отсутствии <code>refresh_token</code> следуйте подсказкам об ошибке: отзовите доступ затем заново пройдите OAuth, либо перейдите на Refresh Token</li></ul><h2 id="предупреждение-к-следующему-уроку" tabindex="-1">Предупреждение к следующему уроку <a class="header-anchor" href="#предупреждение-к-следующему-уроку" aria-label="Permalink to &quot;Предупреждение к следующему уроку&quot;">​</a></h2><blockquote><p>Следующий урок мы делаем более надежное: превращаем пул учетных записей в «актив с возможностью миграции».</p><p>Перейдите к изучению <strong><a href="/docs/opencodedocs/ru/lbjlaq/Antigravity-Manager/start/backup-migrate/">Резервное копирование и миграция: импорт/экспорт, горячая миграция V1/DB</a></strong>.</p><p>Вы узнаете:</p><ul><li>Как экспортировать пул учетных записей в файл JSON (только email + refresh_token)</li><li>Как на новой машине импортировать этот JSON и быстро восстановить пул учетных записей</li></ul></blockquote><hr><h2 id="приложение-ссылки-на-исходныи-код" tabindex="-1">Приложение: ссылки на исходный код <a class="header-anchor" href="#приложение-ссылки-на-исходныи-код" aria-label="Permalink to &quot;Приложение: ссылки на исходный код&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы раскрыть расположение исходного кода</strong></summary><blockquote><p>Дата обновления: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строка</th></tr></thead><tbody><tr><td>Страница Accounts монтирует диалог добавления</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Accounts.tsx#L267-L731" target="_blank" rel="noreferrer"><code>src/pages/Accounts.tsx</code></a></td><td>267-731</td></tr><tr><td>OAuth URL предгенерация + событие автоматического завершения обратного вызова</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L49-L125" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>49-125</td></tr><tr><td>Событие обратного вызова OAuth запускает <code>completeOAuthLogin()</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L67-L109" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>67-109</td></tr><tr><td>Пакетный разбор и дедупликация Refresh Token</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L185-L268" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>185-268</td></tr><tr><td>Фронтенд вызывает команды Tauri (add/OAuth/cancel)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/services/accountService.ts#L5-L91" target="_blank" rel="noreferrer"><code>src/services/accountService.ts</code></a></td><td>5-91</td></tr><tr><td>Бэкенд add_account: игнорирует email, использует refresh_token для получения реального email и сохранения на диск</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L19-L60" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>19-60</td></tr><tr><td>Бэкенд OAuth: проверяет отсутствие refresh_token и дает решение с отозвом</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L38-L79" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>38-79</td></tr><tr><td>Сервер обратного вызова OAuth: одновременно прослушивает IPv4/IPv6 и выбирает redirect_uri</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/oauth_server.rs#L43-L113" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/oauth_server.rs</code></a></td><td>43-113</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Ключевые имена событий</strong>:</p><ul><li><code>oauth-url-generated</code>: после генерации OAuth URL бэкенд отправляет на фронтенд (см. <code>oauth_server.rs:250-252</code>)</li><li><code>oauth-callback-received</code>: после получения обратного вызова и разбора code бэкенд уведомляет фронтенд (см. <code>oauth_server.rs:177-180</code> / <code>oauth_server.rs:232-235</code>)</li></ul><p><strong>Ключевые команды</strong>:</p><ul><li><code>prepare_oauth_url</code>: предгенерировать ссылку авторизации и запустить прослушивание обратного вызова (см. <code>src-tauri/src/commands/mod.rs:469-473</code>)</li><li><code>start_oauth_login</code>: открыть браузер по умолчанию и ждать обратного вызова (см. <code>src-tauri/src/commands/mod.rs:339-401</code>)</li><li><code>complete_oauth_login</code>: не открывать браузер, только ждать обратного вызова и завершить обмен на token (см. <code>src-tauri/src/commands/mod.rs:405-467</code>)</li><li><code>add_account</code>: сохранить учетную запись с помощью refresh_token (см. <code>src-tauri/src/commands/mod.rs:19-60</code>)</li></ul></details>',69)])])}const A=o(c,[["render",d]]);export{g as __pageData,A as default};
